content.query:
union isfuzzy=true
(datatable(d:string)["SpyCloud x SigninLogs",0,1,"SpyCloud x OfficeActivity",0,2,"SpyCloud x CommonSecurityLog",0,3,"SpyCloud x DeviceEvents",0,4,"SpyCloud x BehaviorAnalytics",0,5]),
(let exposedUsers = SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} and severity >= 20 | distinct email;
SigninLogs | where TimeGenerated {TimeRange} | where UserPrincipalName in (exposedUsers) | summarize v=count() | extend Label="SpyCloud x SigninLogs", Order=1 | project Label, Value=v, Order),
(let exposedUsers = SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} and severity >= 20 | distinct email;
OfficeActivity | where TimeGenerated {TimeRange} | where UserId in (exposedUsers) | summarize v=count() | extend Label="SpyCloud x OfficeActivity", Order=2 | project Label, Value=v, Order),
(let spycloudIPs = SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} and isnotempty(ip_address) | distinct tostring(ip_address);
CommonSecurityLog | where TimeGenerated {TimeRange} | where SourceIP in (spycloudIPs) or DestinationIP in (spycloudIPs) | summarize v=count() | extend Label="SpyCloud x CommonSecurityLog", Order=3 | project Label, Value=v, Order),
(let exposedUsers = SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} and severity >= 20 | distinct email;
DeviceEvents | where TimeGenerated {TimeRange} | where AccountUpn in (exposedUsers) | summarize v=count() | extend Label="SpyCloud x DeviceEvents", Order=4 | project Label, Value=v, Order),
(let exposedUsers = SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} and severity >= 20 | distinct email;
BehaviorAnalytics | where TimeGenerated {TimeRange} | where UserPrincipalName in (exposedUsers) | summarize v=count() | extend Label="SpyCloud x BehaviorAnalytics", Order=5 | project Label, Value=v, Order)
| summarize Value=max(Value) by Label, Order
| order by Order asc

union isfuzzy=true
(datatable(d:string)[]),
(let exposedUsers = SpyCloudBreachWatchlist_CL
| where TimeGenerated {TimeRange} and severity >= 20
| distinct email;
let signinCorr = SigninLogs | where TimeGenerated {TimeRange} | where UserPrincipalName in (exposedUsers) | summarize SigninEvents=count() by bin(TimeGenerated, 1d) | extend Source="SigninLogs";
let officeCorr = OfficeActivity | where TimeGenerated {TimeRange} | where UserId in (exposedUsers) | summarize OfficeEvents=count() by bin(TimeGenerated, 1d) | extend Source="OfficeActivity";
let spycloudIngest = SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} and severity >= 20 | summarize SpyCloudEvents=count() by bin(TimeGenerated, 1d) | extend Source="SpyCloud";
union
(signinCorr | project TimeGenerated, Count=SigninEvents, Source),
(officeCorr | project TimeGenerated, Count=OfficeEvents, Source),
(spycloudIngest | project TimeGenerated, Count=SpyCloudEvents, Source)
| order by TimeGenerated asc)
